={{ (() => {
  const comments = [];

  // Parse YouTube comments
  const ytItems = $('▶️ YT – Get Comments').item.json?.body?.items || [];
  ytItems.forEach(item => {
    const c = item.snippet.topLevelComment.snippet;
    comments.push({
      platform: 'YouTube',
      id: item.id,
      author: c.authorDisplayName,
      text: c.textDisplay,
      time: c.publishedAt,
      video_id: c.videoId
    });
  });

  // Parse IG comments
  const igMedia = $('📸 IG – Get Comments').item.json?.body?.data || [];
  igMedia.forEach(media => {
    (media.comments?.data || []).forEach(c => {
      comments.push({
        platform: 'Instagram',
        id: c.id,
        author: c.username,
        text: c.text,
        time: c.timestamp,
        media_id: media.id
      });
    });
  });

  // Sort by time descending
  comments.sort((a, b) => new Date(b.time) - new Date(a.time));

  return JSON.stringify({
    total_comments: comments.length,
    comments: comments.slice(0, 30),
    scan_time: new Date().toISOString()
  });
})() }}

={{ (() => {
  let classified;
  try {
    const content = JSON.parse($json.message.content);
    classified = content.replies || content.comments || content;
    if (!Array.isArray(classified)) classified = [classified];
  } catch(e) {
    classified = [];
  }

  const replyWorthy = classified.filter(c => c.classification === 'reply-worthy');
  const flagged = classified.filter(c => c.classification === 'flag-for-human');
  const ignored = classified.filter(c => c.classification === 'ignore');

  return JSON.stringify({
    total_processed: classified.length,
    reply_worthy: replyWorthy.length,
    flagged: flagged.length,
    ignored: ignored.length,
    replies: replyWorthy,
    flags: flagged,
    scan_time: $('📋 Merge All Comments').item.json.scan_time
  });
})() }}

